define([],function(){"use strict";var initialized=false;function init(){if(initialized)return;initialized=true;document.addEventListener("click",function(e){var btn=e.target.closest(".carrousel-prev-btn,.carrousel-next-btn");if(!btn)return;var wrapper=btn.closest(".carrousel-nav-wrapper");if(!wrapper)return;var container=wrapper.querySelector(".carrousel-scroll-container");if(!container)return;var card=container.querySelector(".carrousel-card-item");var gap=parseFloat(window.getComputedStyle(container).gap)||16;var step=card?(card.offsetWidth+gap):216;var direction=btn.classList.contains("carrousel-prev-btn")?-1:1;container.scrollBy({left:direction*step,behavior:"smooth"});});}return{init:init};});
